import{_ as s,o as i,c as a,ag as t}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"第13章 资源限制与配额","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/13-resource-limits.md","filePath":"chapters/13-resource-limits.md"}'),o={name:"chapters/13-resource-limits.md"};function n(r,e,d,p,c,l){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="第13章-资源限制与配额" tabindex="-1">第13章 资源限制与配额 <a class="header-anchor" href="#第13章-资源限制与配额" aria-label="Permalink to &quot;第13章 资源限制与配额&quot;">​</a></h1><blockquote><p>&quot;资源是有限的，欲望是无穷的。工程师的工作就是在两者之间找到平衡点。&quot; —— Frederick Brooks</p></blockquote><p>AI 沙箱面临一个独特的挑战：运行的代码来自 AI Agent 的生成，其行为不可预测——可能是一个简单的 Python 脚本，也可能是一个意外的死循环或内存泄漏。OpenSandbox 在 API 层、Docker 运行时和 Kubernetes 调度三个层面构建了完整的资源限制体系，确保单个沙箱的资源消耗不会影响整个平台的稳定性。</p><h2 id="api-层-灵活的键值模型" tabindex="-1">API 层：灵活的键值模型 <a class="header-anchor" href="#api-层-灵活的键值模型" aria-label="Permalink to &quot;API 层：灵活的键值模型&quot;">​</a></h2><p>OpenSandbox 的资源限制在 API 层采用了极简的键值对模型。<code>ResourceLimits</code> 被定义为 <code>RootModel[Dict[str, str]]</code>，一个完全开放的字符串字典：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">resource_limits </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;cpu&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;500m&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;512Mi&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;gpu&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>为什么不定义强类型的 schema（如专门的 <code>cpu_cores</code>、<code>memory_bytes</code> 字段）？因为资源类型是不断扩展的。今天是 CPU 和内存，明天可能是 GPU、FPGA、网络带宽。键值对模型让 API 层保持稳定，新资源类型的支持只需要在运行时层添加解析逻辑，无需修改 API 协议。这种设计借鉴了 Kubernetes 资源模型的思路——扩展性优先。</p><h2 id="docker-层-精确的资源解析" tabindex="-1">Docker 层：精确的资源解析 <a class="header-anchor" href="#docker-层-精确的资源解析" aria-label="Permalink to &quot;Docker 层：精确的资源解析&quot;">​</a></h2><p>当请求到达 Docker 运行时后端（<code>server/src/services/docker.py</code>），灵活的字符串值需要被转换为 Docker API 理解的精确数值。两个核心解析函数在 <code>server/src/services/helpers.py</code> 中实现。</p><h3 id="cpu-解析-parse-nano-cpus" tabindex="-1">CPU 解析：parse_nano_cpus() <a class="header-anchor" href="#cpu-解析-parse-nano-cpus" aria-label="Permalink to &quot;CPU 解析：parse_nano_cpus()&quot;">​</a></h3><p>CPU 限制支持两种格式：毫核（如 <code>500m</code> 表示半个 CPU 核心）和整数核心（如 <code>2</code> 表示两个核心）。<code>parse_nano_cpus()</code> 将它们统一转换为纳秒级 CPU 时间，这是 Docker API 的原生单位。<code>500m</code> 转换为 <code>500,000,000</code> 纳秒（即 0.5 核），<code>2</code> 转换为 <code>2,000,000,000</code> 纳秒（即 2 核）。</p><p>为什么单独提供解析函数而非内联处理？因为资源值的格式来自用户输入（可能是 Kubernetes 风格的 <code>500m</code>，也可能是直觉的 <code>0.5</code>），解析逻辑需要处理多种边界情况。独立的函数便于单元测试，也便于未来支持更多格式。</p><h3 id="内存解析-parse-memory-limit" tabindex="-1">内存解析：parse_memory_limit() <a class="header-anchor" href="#内存解析-parse-memory-limit" aria-label="Permalink to &quot;内存解析：parse_memory_limit()&quot;">​</a></h3><p>内存限制支持 Kubernetes 标准后缀：<code>Ki</code>（1024 字节）、<code>Mi</code>（1048576 字节）、<code>Gi</code>（约 10 亿字节）、<code>Ti</code>（约 1 万亿字节）。<code>parse_memory_limit()</code> 将它们转换为字节数。例如 <code>512Mi</code> 转换为 <code>536,870,912</code> 字节。</p><p>这些解析后的数值注入 Docker 的 host config：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mem_limit:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    host_config_kwargs[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mem_limit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mem_limit</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nano_cpus:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    host_config_kwargs[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nano_cpus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nano_cpus</span></span></code></pre></div><h2 id="安全加固-九层防护" tabindex="-1">安全加固：九层防护 <a class="header-anchor" href="#安全加固-九层防护" aria-label="Permalink to &quot;安全加固：九层防护&quot;">​</a></h2><p>Docker 层的资源限制不仅限于 CPU 和内存，<code>_base_host_config_kwargs()</code> 方法构建了完整的安全配置：</p><h3 id="pid-限制" tabindex="-1">PID 限制 <a class="header-anchor" href="#pid-限制" aria-label="Permalink to &quot;PID 限制&quot;">​</a></h3><p><code>pids_limit=512</code> 是容器内的进程数上限。为什么是 512？这个值经过权衡：常规开发工作负载（编译、测试、包安装）通常不会超过几十个进程；512 给了充足的余量，同时有效阻止了 fork 炸弹——一段简单的 <code>while True: os.fork()</code> 代码在 512 个进程后就会被内核拒绝。</p><h3 id="能力丢弃" tabindex="-1">能力丢弃 <a class="header-anchor" href="#能力丢弃" aria-label="Permalink to &quot;能力丢弃&quot;">​</a></h3><p>默认丢弃 9 个 Linux capabilities，包括 <code>NET_ADMIN</code>（网络配置）、<code>SYS_ADMIN</code>（系统管理）等高危权限。AI 生成的代码不应该能修改网络路由表、挂载文件系统或加载内核模块。丢弃这些能力将攻击面最小化。</p><h3 id="权限升级阻止" tabindex="-1">权限升级阻止 <a class="header-anchor" href="#权限升级阻止" aria-label="Permalink to &quot;权限升级阻止&quot;">​</a></h3><p><code>no_new_privileges: true</code> 阻止容器内进程通过 setuid/setgid 二进制文件获取额外权限。即使容器内存在 setuid 程序（如某些包管理器），也无法提权。</p><h3 id="强制访问控制" tabindex="-1">强制访问控制 <a class="header-anchor" href="#强制访问控制" aria-label="Permalink to &quot;强制访问控制&quot;">​</a></h3><p>AppArmor profile 和 Seccomp profile 提供了系统调用级别的过滤。AppArmor 限制文件访问路径和网络行为，Seccomp 限制可用的系统调用集合。两者都通过配置文件指定，允许运维人员根据使用场景调整安全策略：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> docker_cfg.apparmor_profile:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    security_opts.append(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apparmor=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">docker_cfg.apparmor_profile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> docker_cfg.seccomp_profile:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    security_opts.append(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;seccomp=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">docker_cfg.seccomp_profile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="kubernetes-层-弹性资源池" tabindex="-1">Kubernetes 层：弹性资源池 <a class="header-anchor" href="#kubernetes-层-弹性资源池" aria-label="Permalink to &quot;Kubernetes 层：弹性资源池&quot;">​</a></h2><p>在 Kubernetes 运行时中，资源管理上升到集群调度层面。</p><h3 id="pod-资源配额" tabindex="-1">Pod 资源配额 <a class="header-anchor" href="#pod-资源配额" aria-label="Permalink to &quot;Pod 资源配额&quot;">​</a></h3><p>每个沙箱 Pod 通过 <code>resourceRequests</code> 和 <code>resourceLimits</code> 设置资源配额。Requests 是 Kubernetes 调度器的最低保证——调度器确保节点有足够资源满足 request；Limits 是硬上限——超出后容器被 OOM Kill 或 CPU 限流。</p><p><code>ExecdInitResources</code> 为 init container（负责初始化 execd 二进制文件）单独配置资源，避免 init 阶段的临时高资源消耗影响沙箱 Pod 的调度决策。</p><h3 id="pool-crd-容量管理" tabindex="-1">Pool CRD：容量管理 <a class="header-anchor" href="#pool-crd-容量管理" aria-label="Permalink to &quot;Pool CRD：容量管理&quot;">​</a></h3><p>Pool CRD（<code>kubernetes/apis/sandbox/v1alpha1/pool_types.go</code>）定义了资源池的弹性伸缩参数：</p><ul><li><strong>BufferMax/BufferMin</strong>：预热节点的数量范围。预热节点是已创建但未分配的沙箱，用于实现秒级启动。BufferMin 确保始终有一定数量的热备沙箱，BufferMax 控制预热成本。</li><li><strong>PoolMax/PoolMin</strong>：资源池总容量的范围。PoolMax 防止无限扩容，PoolMin 保证最低服务能力。</li></ul><p>所有值都有 <code>minimum: 0</code> 的 schema 验证，防止负数配置导致控制器异常。Pool 的 Status 字段实时报告 <code>Total</code>（总数）、<code>Allocated</code>（已分配）、<code>Available</code>（可用），为运维监控提供数据基础。</p><h2 id="超时限制-时间维度的资源管理" tabindex="-1">超时限制：时间维度的资源管理 <a class="header-anchor" href="#超时限制-时间维度的资源管理" aria-label="Permalink to &quot;超时限制：时间维度的资源管理&quot;">​</a></h2><p>资源不仅是 CPU 和内存，时间也是关键资源。OpenSandbox 在 <code>server/src/config.py</code> 中定义了多层超时：</p><table tabindex="0"><thead><tr><th>配置项</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>max_sandbox_timeout_seconds</code></td><td>可选（最小 60s）</td><td>沙箱生命周期上限</td></tr><tr><td><code>sandbox_create_timeout_seconds</code></td><td>60s</td><td>创建等待超时</td></tr><tr><td><code>sandbox_create_poll_interval_seconds</code></td><td>1.0s</td><td>创建状态轮询间隔</td></tr><tr><td><code>api_timeout</code>（Docker）</td><td>180s</td><td>Docker API 调用超时</td></tr></tbody></table><p><code>max_sandbox_timeout_seconds</code> 是服务端的强制上限，客户端请求的超时不能超过此值。最小 60 秒的限制防止用户设置过短的超时导致沙箱启动都来不及完成。创建超时和轮询间隔的分离设计让系统在等待容器就绪时既不频繁轮询浪费 CPU，又能在合理时间内检测到就绪状态。</p><h2 id="运行时监控-实时资源感知" tabindex="-1">运行时监控：实时资源感知 <a class="header-anchor" href="#运行时监控-实时资源感知" aria-label="Permalink to &quot;运行时监控：实时资源感知&quot;">​</a></h2><p>execd 组件通过 <code>components/execd/pkg/web/controller/metric.go</code> 提供了两种监控接口：</p><ul><li><strong>GET /metrics</strong>：返回当前时刻的 CPU 核心数（<code>runtime.GOMAXPROCS()</code>）、CPU 使用率（gopsutil <code>cpu.Percent()</code>）、内存使用量（MiB）和时间戳。</li><li><strong>GET /metrics/watch</strong>：基于 SSE（Server-Sent Events）的实时监控流，每秒推送一次指标数据。客户端通过标准的 EventSource API 订阅，连接断开自动停止推送。</li></ul><p>为什么选择 SSE 而非 WebSocket？SSE 是单向推送，语义更匹配监控场景（服务器向客户端推数据）；SSE 基于 HTTP，无需升级协议，穿透代理更容易；且 SSE 内建重连机制，网络抖动后自动恢复。</p><p>监控数据使客户端 SDK 能够在资源接近限额时做出预防性决策，例如在内存接近上限前主动释放缓存或终止内存密集型任务。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>OpenSandbox 的资源管理体系体现了 <strong>分层防御</strong> 的设计哲学：API 层提供灵活的键值模型保证扩展性，Docker 层将其转化为精确的运行时约束（CPU/内存/PID/能力/权限），Kubernetes 层在集群维度实现弹性调度和容量管理，超时体系从时间维度约束资源使用。每一层都假设上一层可能失效，提供独立的保护。关键源码路径：<code>server/src/api/schema.py</code>（API 模型）、<code>server/src/services/helpers.py</code>（资源解析）、<code>server/src/services/docker.py</code>（Docker 安全配置）、<code>server/src/config.py</code>（超时与默认值）、<code>kubernetes/apis/sandbox/v1alpha1/pool_types.go</code>（Pool CRD）、<code>components/execd/pkg/web/controller/metric.go</code>（运行时监控）。</p>`,47)])])}const u=s(o,[["render",n]]);export{k as __pageData,u as default};
